   399→impl Fit for LmFit {
   400→    fn coefficients(&self) -> &[f64] {
   401→        &self.coefficients
   402→    }
   403→
   404→    fn fitted(&self) -> &[f64] {
   405→        &self.fitted_values
   406→    }
   407→
   408→    fn residuals(&self) -> &[f64] {
   409→        &self.residuals
   410→    }
   411→
   412→    fn summary(&self) -> ModelSummary {
   413→        use inference::{f_test_p_value, model_f_statistic, t_statistics, t_test_p_values};
   414→
   415→        // Calculate residual standard error: s² = RSS / (n - p)
   416→        let rss: f64 = self.residuals.iter().map(|r| r * r).sum();
   417→        let df_resid = self.df_resid() as f64;
   418→        let mse = if df_resid > 0.0 { rss / df_resid } else { 0.0 };
   419→        let residual_std_error = mse.sqrt();
   420→
   421→        // Calculate Total Sum of Squares (TSS) and R-squared
   422→        let y_mean: f64 = self
   423→            .fitted_values
   424→            .iter()
   425→            .zip(self.residuals.iter())
   426→            .map(|(fitted, resid)| fitted + resid) // y = fitted + residual
   427→            .sum::<f64>()
   428→            / self.n_obs as f64;
   429→
   430→        let tss: f64 = self
   431→            .fitted_values
   432→            .iter()
   433→            .zip(self.residuals.iter())
   434→            .map(|(fitted, resid)| {
   435→                let y = fitted + resid;
   436→                (y - y_mean).powi(2)
   437→            })
   438→            .sum();
   439→
   440→        let r_squared = if tss > 0.0 { 1.0 - rss / tss } else { 0.0 };
   441→
   442→        // Adjusted R-squared: 1 - (RSS/(n-p)) / (TSS/(n-1))
   443→        let n = self.n_obs as f64;
   444→        let p = self.rank as f64;
   445→        let adj_r_squared = if n > 1.0 && p > 0.0 {
   446→            1.0 - (rss / (n - p)) / (tss / (n - 1.0))
   447→        } else {
   448→            r_squared
   449→        };
   450→
   451→        // F-statistic for overall model significance
   452→        // RSS for null model (intercept only) equals TSS
   453→        let df_model = if self.rank > 1 { self.rank - 1 } else { 0 }; // exclude intercept
   454→        let f_statistic = if df_model > 0 {
   455→            model_f_statistic(rss, tss, df_model, self.df_resid())
   456→        } else {
   457→            0.0
   458→        };
   459→
   460→        let f_p_value = if df_model > 0 && self.df_resid() > 0 {
   461→            f_test_p_value(f_statistic, df_model as i32, self.df_resid() as i32)
   462→        } else {
   463→            1.0
   464→        };
   465→
   466→        // Calculate variance-covariance matrix: σ² * (X'X)^(-1)
   467→        // Compute X'X
   468→        let xtx = self.x_matrix.transpose() * &self.x_matrix;
   469→
   470→        // Compute (X'X)^(-1) - use QR decomposition for numerical stability
   471→        let qr = xtx.col_piv_qr();
   472→        let identity = Mat::identity(xtx.nrows(), xtx.ncols());
   473→        let xtx_inv = qr.solve(&identity);
   474→
   475→        // Standard errors are sqrt of diagonal elements of σ² * (X'X)^(-1)
   476→        let std_errors: Vec<f64> = (0..self.coefficients.len())
   477→            .map(|i| (mse * xtx_inv[(i, i)]).sqrt())
   478→            .collect();
   479→
   480→        let t_stats = t_statistics(&self.coefficients, &std_errors);
   481→        let p_values = t_test_p_values(&t_stats, self.df_resid() as i32);
   482→
   483→        let mut coefficient_rows = Vec::new();
   484→        for (i, &coef) in self.coefficients.iter().enumerate() {
   485→            let name = if i == 0 {
   486→                "Intercept".to_string()
   487→            } else {
   488→                format!("X{}", i)
   489→            };
   490→
   491→            coefficient_rows.push(CoefficientRow {
   492→                name,
   493→                estimate: coef,
   494→                std_error: std_errors[i],
   495→                t_value: t_stats[i],
   496→                p_value: p_values[i],
   497→            });
   498→        }
   499→
   500→        ModelSummary {
   501→            coefficients: coefficient_rows,
   502→            r_squared,
   503→            adj_r_squared,
   504→            residual_std_error,
   505→            f_statistic,
   506→            f_p_value,
   507→            df_model,
   508→            df_residual: self.df_resid(),
   509→        }
   510→    }
   511→}
